from flask import Flask, render_template, request
from prometheus_client import start_wsgi_server, Counter, Gauge, Histogram

app = Flask(__name__)

# Define metrics
request_counter = Counter('app_requests_total', 'Total number of requests')
request_latency = Histogram('app_request_latency_seconds', 'Request latency in seconds')
business_metric = Gauge('app_business_metric', 'Value of the business metric')

@app.route('/')
def home():
    request_counter.inc()
    request_latency.observe(request.duration_seconds)
    business_metric.set(42)
    return render_template('index.html')

if __name__ == '__main__':
    start_wsgi_server(app)